import{parse as twemojiParse}from"twemoji";import{DateTime}from"luxon";const newsContainer=document.getElementById("news-container");fetch("/api/news",{method:"GET"}).then(e=>{e.json().then(e=>{e.data.forEach(e=>{let t=document.createElement("li"),n=document.createElement("a"),a=document.createElement("h6");n.href=`/news/${e.id}`,n.innerText=e.title,a.textContent=`(${DateTime.fromISO(e.created_at).toRelativeCalendar()})`,twemojiParse(n),t.appendChild(n),t.appendChild(a),newsContainer.appendChild(t)})})});